  sel.innerHTML = '<option value="">Match team…</option>' + roster.map((r) => `<option value="${_wlEsc(r.entrantId)}">${_wlEsc(r.name || 'Team')}</option>`).join('');
  const ts = currentState.teamSpotlight || {};
